INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('aboriginal-6f0ba476-moex-00250', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-112-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '下列關於意思表示之敘述，何者正確？', '["法律行為，係乘他人之急迫、輕率或無經驗，使其為財產上給付或為給付之約定，毋待向法院 聲請撤銷，當然無效", "通謀虛偽意思表示而隱藏他項法律行為者，該二行為均無效", "單獨虛偽意思表示，不因之無效。但其情形為相對人明知者，則無效", "表意人受第三人之脅迫而為意思表示，如相對人為善意者，則不得撤銷"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:54+00:00", "source_pdf_sha1": "24a86a5609a7", "answer_pdf_sha1": "239ddc873623", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00251', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-112-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '依民法關於代理之規定，下列敘述何者正確？', '["代理人得自為意思表示與受意思表示，故代理人即視為本人", "代理人得為法律行為、準法律行為與事實行為", "意思表示瑕疵之認定，係完全就代理人決定之", "代理人所為或所受意思表示之效力，不因其為限制行為能力人而受影響"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:54+00:00", "source_pdf_sha1": "24a86a5609a7", "answer_pdf_sha1": "239ddc873623", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00252', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-112-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '甲到乙超商，以新臺幣50元硬幣一枚，購買一瓶礦泉水；甲付錢，乙給水，銀貨兩訖。整個交易 過程，下列敘述何者正確？', '["甲與乙超商雙方總共就只有訂立一個買賣契約", "甲與乙超商訂立一個買賣契約及一個物權契約", "甲與乙超商訂立一個買賣契約及二個物權契約", "甲與乙超商訂立一個買賣契約及三個物權契約"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:54+00:00", "source_pdf_sha1": "24a86a5609a7", "answer_pdf_sha1": "239ddc873623", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00253', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-112-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '甲向丙購地，借用乙之姓名辦理所有權移轉登記，下列敘述何者正確？', '["甲乙間之借名登記契約，係屬通謀虛偽表示", "甲乙間之借名登記契約，均屬違反公序良俗", "乙將該地讓與知情之丁，實務上，係屬無權處分", "甲指示乙將該地讓與戊，實務上，係屬有權處分"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:54+00:00", "source_pdf_sha1": "24a86a5609a7", "answer_pdf_sha1": "239ddc873623", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00254', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-112-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '下列關於消費者保護法（下稱消保法）之責任主體及其保護對象之敘述，何者正確？', '["輸入商品之進口商，對商品之安全性欠缺，不須負消保法之無過失責任", "非以營利為目的而提供商品，倘若提供之商品與其營業有關，就商品之安全性欠缺，須負消保 法之無過失責任", "醫師基於其專業之知識，就病患之病情及身體狀況選擇最適宜之醫療方式進行醫療，就該醫療 服務之瑕疵，原則上，亦須負消保法之無過失責任", "非所有因公司經營者提供之商品或服務而遭受人身或財物損害之人，均得依消保法請求救濟"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:54+00:00", "source_pdf_sha1": "24a86a5609a7", "answer_pdf_sha1": "239ddc873623", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00255', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-112-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '下列關於合會契約之敘述，何者正確？', '["會首及會員以自然人為限", "無行為能力人得為合會會首", "限制行為能力人得為合會會首", "會首得兼為同一合會之會員"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:54+00:00", "source_pdf_sha1": "24a86a5609a7", "answer_pdf_sha1": "239ddc873623", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00256', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-112-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '甲提供其所有之A不動產供乙設定普通抵押權，以擔保乙對丙之新臺幣300萬元債權。就丙於清 償期屆至時卻無力清償之情形，下列敘述何者正確？', '["丙之友人丁如欲代丙清償時，即使丙有異議，乙仍得受領之", "丙之父戊如欲代丙清償時，因丙有異議，乙即應拒絕其清償", "甲如欲代丙清償時，因丙有異議，乙即應拒絕其清償", "甲如欲代丙清償時，即使丙無異議，乙仍應拒絕其清償"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:54+00:00", "source_pdf_sha1": "24a86a5609a7", "answer_pdf_sha1": "239ddc873623", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00257', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-112-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '甲於其配偶丙出國期間，將丙所有之 A 車交付乙並免費借於乙使用，言明 3 個月後丙返國時歸 還。下列敘述何者正確？', '["甲並非A車所有人，甲乙間借貸契約，應經丙之承認，始生效力", "甲並非A車所有人，借用期滿，甲不得請求乙返還A車", "若甲僅是口頭與乙約定，要將 A 車於丙出國期間借於乙使用，則甲交付 A 車前，可以反悔不 借，乙不得請求甲交付A車", "乙係無償借用，應以處理自己事務之同一注意義務保管A車"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:54+00:00", "source_pdf_sha1": "24a86a5609a7", "answer_pdf_sha1": "239ddc873623", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00258', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-112-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '甲與乙訂立買賣契約，將A地出賣於乙，乙何時取得A地之所有權？', '["甲與乙之買賣契約有效成立時", "甲與乙之買賣契約完成公證時", "甲交付A地於買受人乙占有時", "甲與乙完成所有權移轉登記時"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:54+00:00", "source_pdf_sha1": "24a86a5609a7", "answer_pdf_sha1": "239ddc873623", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00259', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-112-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '下列何者構成買賣之權利瑕疵？', '["買賣之房屋為凶宅", "買賣之公寓大廈之公共管線漏水", "第三人就該買賣建地設定普通地上權", "買賣之土地因為魚塭地而不得建高樓"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:54+00:00", "source_pdf_sha1": "24a86a5609a7", "answer_pdf_sha1": "239ddc873623", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL)
